class Solution:
    def inorderTraversal(self, root) -> list[int]:
        out, stack, cur = [], [], root
        while cur or stack:
            while cur:
                stack.append(cur)
                cur = cur.left
            cur = stack.pop()
            out.append(cur.val)
            cur = cur.right
        return out

class Solution:
    def inorderTraversal(self, root) -> list[int]:
        out: list[int] = []

        def dfs(n):
            if not n:
                return
            dfs(n.left)
            out.append(n.val)
            dfs(n.right)

        dfs(root)
        return out

class Solution:
    def inorderTraversal(self, root) -> list[int]:
        out: list[int] = []
        cur = root
        while cur:
            if cur.left:
                pred = cur.left
                while pred.right and pred.right is not cur:
                    pred = pred.right
                if pred.right is None:
                    pred.right = cur
                    cur = cur.left
                else:
                    pred.right = None       # 恢复
                    out.append(cur.val)
                    cur = cur.right
            else:
                out.append(cur.val)
                cur = cur.right
        return out
